mapper.select:
/* TM_ME31001_Dao_retrieveElyrsEltengMsrinsList */ SELECT setcsc_nm, dept_nm, elcpwstn_nm, ecs_elcpwstn_div_cd, mrnr_nm, eqp_cpcty, eqp_div_info, mnfctr_ym, eror_exam_hist_ym, eror_exam_plan_ym, nation_athrz_hist_ym, nation_athrz_plan_ym, cdm_exam_cycle_pd, cdm_grp_id, rm_ctnt, frst_regist_dt, frst_rgstr_id, last_updt_dt, last_updusr_id, updt_rsn FROM ( SELECT /*+ LEADING(B A) */ ( SELECT DECODE(cmmn_cd, '0004', '태양광', '0005', '태양광', '0007', '보소수력', cmmn_cd_nm ) AS cmmn_cd_nm FROM SCM.tc_sc_unif_cmmn_cd WHERE sys_div_cd = 'WRO' AND cls_cd = 'WRO_3003' AND cmmn_cd = B.elcpwstn_cls_cd ) AS setcsc_nm, B.elcpwstn_cls_cd AS setcsc_cd, ( SELECT stext FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND objid IN ( SELECT DISTINCT CASE WHEN MIN(depth) OVER(PARTITION BY kostl) = depth THEN objid ELSE NULL END FROM HRM.vm_hr01a01 WHERE SYSDATE BETWEEN strdt AND enddt AND TRIM(kostl) IS NOT NULL ) AND kostl = LPAD(B.cstct_vu, 10, '0') ) AS dept_nm, B.cstct_vu AS dept_cd, B.elcpwstn_nm AS elcpwstn_nm, A.ecs_elcpwstn_div_cd, A.mrnr_nm, A.eqp_cpcty, A.eqp_div_info, A.mnfctr_ym, A.eror_exam_hist_ym, A.eror_exam_plan_ym, A.nation_athrz_hist_ym, A.nation_athrz_plan_ym, A.cdm_exam_cycle_pd, A.cdm_grp_id, A.rm_ctnt, DECODE(elcpwstn_cls_cd, '0005', B.dsply_ordr + 9000, B.dsply_ordr) AS dsply_ordr, A.frst_regist_dt, A.frst_rgstr_id, A.last_updt_dt, A.last_updusr_id, A.updt_rsn FROM tm_me31001 A LEFT JOIN WRO.tc_eg10101 B ON A.ecs_elcpwstn_div_cd = B.elcpwstn_cd WHERE 1 = 1
AND B.cstct_vu = #{ecsChrgDeptId}
AND A.ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
) ORDER BY dsply_ordr

mapper.delete:
/* TM_ME31001_Dao_deleteElyrsEltengMsrinsList */
DELETE FROM
	tm_me31001
WHERE
	ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
	AND mrnr_nm = #{mrnrNm}
